from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent, combined sentence."""
    if not triples:
        return ""

    from collections import defaultdict

    # Group triples by their subject so we can build one sentence per entity
    grouped = defaultdict(list)
    for t in triples:
        grouped[t.subject].append(t)

    result_sentences = []

    for subj, tlist in grouped.items():
        parts = []

        # Birth information
        birth_dates = [t.object for t in tlist if t.predicate == "birthDate"]
        birth_years = [t.object for t in tlist if t.predicate == "birthYear"]
        birth_places = [t.object for t in tlist if t.predicate == "birthPlace"]
        if birth_dates:
            parts.append(f"was born on {birth_dates[0]}")
        elif birth_years:
            parts.append(f"was born in {birth_years[0]}")
        if birth_places:
            parts.append(f"in {birth_places[0]}")

        # Physical attributes
        heights = [t.object for t in tlist if t.predicate == "height"]
        if heights:
            parts.append(f"is {heights[0]} metres tall")
        weights = [t.object for t in tlist if t.predicate == "weight"]
        if weights:
            parts.append(f"weighs {weights[0]}")

        # Position
        positions = [t.object for t in tlist if t.predicate == "position"]
        if positions:
            parts.append(f"plays as a {positions[0]}")

        # Current clubs / teams
        clubs = [t.object for t in tlist if t.predicate in ("club", "currentteam", "currentclub")]
        if clubs:
            parts.append(f"plays for {', '.join(clubs)}")

        # Former teams
        former = [t.object for t in tlist if t.predicate == "formerTeam"]
        if former:
            parts.append(f"formerly played for {', '.join(former)}")

        # League
        leagues = [t.object for t in tlist if t.predicate == "league"]
        if leagues:
            parts.append(f"competes in the {leagues[0]} league")

        # Manager / coach
        managers = [t.object for t in tlist if t.predicate == "manager"]
        if managers:
            parts.append(f"is managed by {managers[0]}")

        # Ground / stadium
        grounds = [t.object for t in tlist if t.predicate == "ground"]
        if grounds:
            parts.append(f"home ground is {grounds[0]}")

        # Other predicates – simple fallback
        handled = {"birthDate","birthYear","birthPlace","height","weight","position",
                   "club","currentteam","currentclub","formerTeam","league","manager","ground"}
        for t in tlist:
            if t.predicate not in handled:
                parts.append(f"{t.predicate.replace('_',' ')} {t.object}")

        # Assemble the sentence for this subject
        if parts:
            sentence = f"{subj} " + ", ".join(parts) + "."
        else:
            sentence = f"{subj}."
        result_sentences.append(sentence)

    # Join sentences for different subjects with a space
    return " ".join(result_sentences)

# EVOLVE-BLOCK-END

